let db;let currentTaskRef=null;let draggedItem=null;let selectedImg=null;document.addEventListener("DOMContentLoaded",()=>{if("serviceWorker" in navigator){navigator.serviceWorker .register("sw.js").then(()=>console.log("Service Worker Registered")).catch((err)=>console.error("SW Registration Failed",err));}if("Notification" in window && Notification.permission==="default"){Notification.requestPermission();}});function sendNotification(title,text){if("Notification" in window && Notification.permission==="granted" && navigator.serviceWorker.controller){navigator.serviceWorker.controller.postMessage({type:"text",title:title,text:text,icon:"https://www.darpanadhikari.com.np/addition/images/logo.ico",});}}const request=indexedDB.open("TrelloSmoothDB",1);request.onupgradeneeded=(e)=>{db=e.target.result;db.createObjectStore("users",{keyPath:"name"});};request.onsuccess=(e)=>{db=e.target.result;render();};function exec(cmd,val=null){document.execCommand(cmd,false,val);}function updateUser(uName,cb){const tx=db.transaction("users","readwrite");const store=tx.objectStore("users");store.get(uName).onsuccess=(e)=>{const u=e.target.result;if(u){cb(u);store.put(u);}tx.oncomplete=render;};}function handleDragStart(e,uName,bTitle,tId){draggedItem={uName,bTitle,tId};e.dataTransfer.effectAllowed="move";setTimeout(()=>e.target.classList.add("dragging"),0);}function handleDragEnd(e){e.target.classList.remove("dragging");setTimeout(()=>(draggedItem=null),10);}function handleDragOver(e){e.preventDefault();e.dataTransfer.dropEffect="move";}function handleDrop(e,targetUName,targetBTitle){e.preventDefault();if(!draggedItem)return;const item={...draggedItem};if(item.uName!==targetUName){alert("Cross-workspace dragging is disabled.");return;}const container=e.currentTarget;const afterElement=getDragAfterElement(container,e.clientY);const targetId=afterElement?Number(afterElement.dataset.id):null;updateUser(item.uName,(u)=>{const sourceBoard=u.boards.find((b)=>b.title===item.bTitle);const targetBoard=u.boards.find((b)=>b.title===targetBTitle);if(!sourceBoard||!targetBoard)return;const taskIndex=sourceBoard.tasks.findIndex((t)=>t.id===item.tId);if(taskIndex===-1)return;const [movedTask]=sourceBoard.tasks.splice(taskIndex,1);if(targetId===null){targetBoard.tasks.push(movedTask);}else{const insertIndex=targetBoard.tasks.findIndex((t)=>t.id===targetId);targetBoard.tasks.splice(insertIndex,0,movedTask);}});sendNotification("Card Moved",`Card was moved to list "${targetBTitle}".`);}function getDragAfterElement(container,y){const draggableElements=[ ...container.querySelectorAll(".task:not(.dragging)"),];return draggableElements.reduce((closest,child)=>{const box=child.getBoundingClientRect();const offset=y-box.top-box.height / 2;if(offset<0 && offset>closest.offset){return{offset:offset,element:child};}else{return closest;}},{offset:Number.NEGATIVE_INFINITY}).element;}function addUser(){const name=document.getElementById("newWorkspace").value.trim();if(!name)return;const tx=db.transaction("users","readwrite");tx.objectStore("users").add({name,collapsed:false,boards:[]});tx.oncomplete=()=>{document.getElementById("newWorkspace").value="";render();sendNotification("Workspace Created",`Workspace "${name}" is ready.`);};}function addBoard(uName){const val=document.getElementById(`nb-${uName}`).value.trim();if(!val)return;updateUser(uName,(u)=>u.boards.push({title:val,tasks:[]}));sendNotification("List Added",`List "${val}" was added to ${uName}.`);}function deleteBoard(uName,bTitle){if(!confirm("Delete this list?"))return;updateUser(uName,(u)=>{u.boards=u.boards.filter((b)=>b.title!==bTitle);});sendNotification("List Deleted",`List "${bTitle}" was removed.`);}function addTask(uName,bTitle){const val=document.getElementById(`nt-${uName}-${bTitle}`).value.trim();if(!val)return;updateUser(uName,(u)=>{u.boards .find((x)=>x.title===bTitle).tasks.push({id:Date.now(),title:val,desc:"",html:"",cover:null,});});sendNotification("Card Added",`Card "${val}" added to ${bTitle}.`);}function deleteTask(uName,bTitle,tId){if(!confirm("Delete this card entirely?"))return;updateUser(uName,(u)=>{const b=u.boards.find((x)=>x.title===bTitle);b.tasks=b.tasks.filter((t)=>t.id!==tId);});sendNotification("Card Deleted",`A card was removed from ${bTitle}.`);}function deleteWorkspace(uName){if(!confirm(`Are you sure you want to delete the workspace "${uName}" and all its lists?`))return;const tx=db.transaction("users","readwrite");tx.objectStore("users").delete(uName);tx.oncomplete=()=>{render();sendNotification("Workspace Deleted",`Workspace "${uName}" was permanently deleted.`);};}function toggleWorkspace(uName){updateUser(uName,(u)=>(u.collapsed=!u.collapsed));}let fileHandle;async function exportData(){const tx=db.transaction("users","readonly");const req=tx.objectStore("users").getAll();req.onsuccess=async(e)=>{const data=e.target.result;const jsonStr=JSON.stringify(data);const encryptedData=btoa(unescape(encodeURIComponent(jsonStr)));if(!fileHandle){const firstTitle=document .querySelector(".workspace-header-title span:nth-child(2)").textContent.trim();fileHandle=await window.showSaveFilePicker({suggestedName:`${firstTitle}.drp`,types:[{description:"Darpan Tasks organizer Export developed by darpanadhikari.com.np",accept:{"application/octet-stream":[".drp"]},},],});}const writable=await fileHandle.createWritable();await writable.write(encryptedData);await writable.close();sendNotification("Export Successful","Tasks exported and file replaced.");};}function importData(){const input=document.createElement("input");input.type="file";input.accept=".drp";input.onchange=(e)=>{const file=e.target.files[0];if(!file)return;const reader=new FileReader();reader.onload=(event)=>{try{const encryptedData=event.target.result;const jsonStr=decodeURIComponent(escape(atob(encryptedData)));const importedWorkspaces=JSON.parse(jsonStr);mergeImportedData(importedWorkspaces);}catch(error){alert("Error:Invalid or corrupted .drp file. Ensure it was exported from this software.");}};reader.readAsText(file);};input.click();}function mergeImportedData(importedWorkspaces){if(!Array.isArray(importedWorkspaces))return alert("Invalid data format.");const tx=db.transaction("users","readwrite");const store=tx.objectStore("users");store.getAll().onsuccess=(e)=>{const existingWorkspaces=e.target.result;importedWorkspaces.forEach((impWs)=>{const exWs=existingWorkspaces.find((w)=>w.name===impWs.name);if(!exWs){store.add(impWs);}else{let needsUpdate=false;impWs.boards.forEach((impBoard)=>{const exBoard=exWs.boards.find((b)=>b.title===impBoard.title);if(!exBoard){exWs.boards.push(impBoard);needsUpdate=true;}else{impBoard.tasks.forEach((impTask)=>{const exTask=exBoard.tasks.find((t)=>t.id===impTask.id);if(!exTask){exBoard.tasks.push(impTask);needsUpdate=true;}});}});if(needsUpdate)store.put(exWs);}});};tx.oncomplete=()=>{alert("Data successfully imported and merged without overwriting existing items.");render();sendNotification("Import Successful","Your .drp tasks have been merged into your workspace.");};}function openModal(e,uName,bTitle,tId){if(e.target.closest(".small-btn"))return;const tx=db.transaction("users","readonly");tx.objectStore("users").get(uName).onsuccess=(event)=>{const task=event.target.result.boards .find((b)=>b.title===bTitle).tasks.find((t)=>t.id===tId);currentTaskRef={uName,bTitle,tId};document.getElementById("modalTitle").value=task.title;document.getElementById("modalDesc").innerHTML=task.html||task.desc;document.getElementById("modalOverlay").classList.add("active");selectedImg=null;};}function closeModal(){document.getElementById("modalOverlay").classList.remove("active");}function openViewModal(e,uName,bTitle,tId){e.stopPropagation();const tx=db.transaction("users","readonly");tx.objectStore("users").get(uName).onsuccess=(event)=>{const task=event.target.result.boards .find((b)=>b.title===bTitle).tasks.find((t)=>t.id===tId);document.getElementById("viewModalTitle").innerText=task.title;document.getElementById("viewModalDesc").innerHTML=task.html||task.desc||"<i>No description provided.</i>";document.getElementById("viewModalOverlay").classList.add("active");};}function closeViewModal(e){if(e)e.stopPropagation();document.getElementById("viewModalOverlay").classList.remove("active");}function extractCoverImage(htmlString){const tempDiv=document.createElement("div");tempDiv.innerHTML=htmlString;const img=tempDiv.querySelector("img");return img?img.src:null;}function saveChanges(){if(!currentTaskRef)return closeModal();const newTitle=document.getElementById("modalTitle").value;const newHtml=document.getElementById("modalDesc").innerHTML;const plainText=document.getElementById("modalDesc").innerText;const coverImgSrc=extractCoverImage(newHtml);updateUser(currentTaskRef.uName,(u)=>{const board=u.boards.find((x)=>x.title===currentTaskRef.bTitle);if(!board)return;const t=board.tasks.find((x)=>x.id===currentTaskRef.tId);if(!t)return;t.title=newTitle;t.html=newHtml;t.desc=plainText.substring(0,120);t.cover=coverImgSrc;});closeModal();sendNotification("Card Updated",`Changes to "${newTitle}" were saved.`);}function render(){const searchQuery=document .getElementById("searchInput").value.toLowerCase();const req=db.transaction("users").objectStore("users").getAll();req.onsuccess=(e)=>{const root=document.getElementById("workspaces");root.innerHTML="";const users=e.target.result;users.forEach((u)=>{let matchesSearch=false;let filteredBoards=[];if(u.name.toLowerCase().includes(searchQuery)){matchesSearch=true;filteredBoards=u.boards;}else{u.boards.forEach((b)=>{if(b.title.toLowerCase().includes(searchQuery)){matchesSearch=true;filteredBoards.push(b);}else{const matchedTasks=b.tasks.filter((t)=>t.title.toLowerCase().includes(searchQuery)||(t.desc && t.desc.toLowerCase().includes(searchQuery)));if(matchedTasks.length>0){matchesSearch=true;filteredBoards.push({...b,tasks:matchedTasks});}}});}if(searchQuery &&!matchesSearch)return;const boardsToRender=searchQuery?filteredBoards:u.boards;const div=document.createElement("div");div.className=`workspace ${u.collapsed &&!searchQuery?"collapsed":""}`;div.innerHTML=`<div class="workspace-header" onclick="toggleWorkspace('${u.name}')"><div class="workspace-header-title"><span class="toggle-icon">▼</span><span ondblclick="renameWorkspace('${u.name}')">${u.name}</span></div><button class="small-btn del-btn" onclick="event.stopPropagation();deleteWorkspace('${u.name}')">Delete Workspace</button></div><div class="board-list">${boardsToRender .map((b)=>{let backColor=getSoftColor();let borderColor=getSoftColor();return `<div class="board" style="background:${backColor};"><div class="board-header"><h3 ondblclick="renameBoard('${u.name}','${b.title}')">${b.title}</h3><button class="small-btn del-btn" onclick="deleteBoard('${u.name}','${b.title}')">Delete</button></div><div class="tasks" ondragover="handleDragOver(event)" ondrop="handleDrop(event,'${u.name}','${b.title}')">${b.tasks .map((t)=>`<div class="task" draggable="true" data-id="${t.id}" style="background:${backColor};border:2px dashed ${borderColor};" ondragstart="handleDragStart(event,'${u.name}','${b.title}',${t.id})" ondragend="handleDragEnd(event)" onclick="openModal(event,'${u.name}','${b.title}',${t.id})">${t.cover?`<img src="${t.cover}" class="task-cover">`:""}<div class="task-content"><span class="task-title">${t.title}</span>${t.desc?`<div class="task-desc-preview">${t.desc}</div>`:""}<div class="card-btns"><button class="small-btn view-btn" onclick="openViewModal(event,'${u.name}','${b.title}',${t.id})">View</button><button class="small-btn del-btn" onclick="event.stopPropagation();deleteTask('${u.name}','${b.title}',${t.id})">Delete</button></div></div></div>`).join("")}</div><div class="input-group"><input type="text" id="nt-${u.name}-${b.title}" placeholder="Add a card..." onkeypress="if(event.key==='Enter')addTask('${u.name}','${b.title}')"><button class="btn-primary" onclick="addTask('${u.name}','${b.title}')">Add Card</button></div></div>`;}).join("")}<div class="board" style="background:rgba(255,255,255,0.8);border:2px dashed rgba(0,0,0,0.1);box-shadow:none;"><div class="input-group" style="border-top:none;"><input type="text" id="nb-${u.name}" placeholder="New list name..." onkeypress="if(event.key==='Enter')addBoard('${u.name}')"><button class="btn-primary" onclick="addBoard('${u.name}')">Add List</button></div></div></div>`;root.appendChild(div);});};}function getSoftColor(){const r=Math.floor(Math.random()* 127+127);const g=Math.floor(Math.random()* 127+127);const b=Math.floor(Math.random()* 127+127);return `rgb(${r},${g},${b})`;}function renameWorkspace(oldName){const newName=prompt("Enter new workspace name:",oldName);if(!newName||newName.trim()===""||newName===oldName)return;const tx=db.transaction("users","readwrite");const store=tx.objectStore("users");store.get(oldName).onsuccess=(e)=>{const data=e.target.result;if(!data)return;data.name=newName.trim();store.delete(oldName);store.add(data);tx.oncomplete=()=>{render();sendNotification("Workspace Renamed",`"${oldName}" → "${newName}"`);};};}function renameBoard(uName,oldTitle){const newTitle=prompt("Enter new list name:",oldTitle);if(!newTitle||newTitle.trim()===""||newTitle===oldTitle)return;updateUser(uName,(u)=>{const board=u.boards.find((b)=>b.title===oldTitle);if(board){board.title=newTitle.trim();}});sendNotification("List Renamed",`"${oldTitle}" → "${newTitle}"`);}function insertCode(){const sel=window.getSelection();if(sel.rangeCount && sel.toString().length>0){const code=document.createElement("code");code.textContent=sel.toString();const range=sel.getRangeAt(0);range.deleteContents();range.insertNode(code);}else{document.execCommand("insertHTML",false,"<code>code</code>&nbsp;");}}function insertPre(){document.execCommand("formatBlock",false,"PRE");const node=window.getSelection().anchorNode;const pre=node.nodeType===3?node.parentNode.closest("pre"):node.closest("pre");if(pre)pre.className="code-block";}function insertQuote(){document.execCommand("formatBlock",false,"BLOCKQUOTE");}function insertHR(){document.execCommand("insertHorizontalRule");}function insertLink(){const url=prompt("Enter URL(e.g.,https://google.com):");if(!url)return;document.execCommand("createLink",false,url);}function clearFormat(){document.execCommand("removeFormat");document.execCommand("formatBlock",false,"p");}document.getElementById("modalDesc").addEventListener("click",(e)=>{if(e.target.tagName==="IMG"){if(selectedImg)selectedImg.style.outline="none";selectedImg=e.target;selectedImg.style.outline="3px solid var(--btn-primary)";}else{if(selectedImg){selectedImg.style.outline="none";selectedImg=null;}}});function imgFloat(alignment){if(selectedImg){selectedImg.style.display=alignment==="none"?"block":"inline";selectedImg.style.float=alignment;selectedImg.style.margin=alignment==="none"?"10px auto":"10px";}else{alert("Please click an image first to select it.");}}function imgSize(size){if(selectedImg){selectedImg.style.width=size;}else{alert("Please click an image first to select it.");}}document.getElementById("modalDesc").addEventListener("keydown",(e)=>{if(e.key==="Enter"){const sel=window.getSelection();const node=sel.anchorNode;if(node && node.parentElement.closest("pre")){e.preventDefault();document.execCommand("insertHTML",false,"</pre><p><br></p>");}}});const editor=document.getElementById("modalDesc");editor.addEventListener("click",(e)=>{if(e.target.tagName==="IMG"){if(selectedImg)selectedImg.style.outline="none";selectedImg=e.target;selectedImg.style.outline="3px solid var(--btn-primary)";}else if(selectedImg){selectedImg.style.outline="none";selectedImg=null;}});function compressImage(file,maxWidth=800,quality=0.7,callback){const reader=new FileReader();reader.onload=(e)=>{const img=new Image();img.onload=()=>{const ratio=Math.min(1,maxWidth / img.width);const canvas=document.createElement("canvas");canvas.width=img.width * ratio;canvas.height=img.height * ratio;canvas.getContext("2d").drawImage(img,0,0,canvas.width,canvas.height);canvas.toBlob((blob)=>callback(blob),"image/jpeg",quality);};img.src=e.target.result;};reader.readAsDataURL(file);}function insertImageBlob(blob){const reader=new FileReader();reader.onload=function(e){const img=document.createElement("img");img.src=e.target.result;img.style.maxWidth="100%";const sel=window.getSelection();if(!sel.rangeCount)return;const range=sel.getRangeAt(0);range.insertNode(img);range.setStartAfter(img);range.collapse(true);};reader.readAsDataURL(blob);}editor.addEventListener("dragover",(e)=>e.preventDefault());editor.addEventListener("drop",(e)=>{e.preventDefault();const file=e.dataTransfer.files[0];if(!file||!file.type.startsWith("image/"))return;compressImage(file,800,0.7,insertImageBlob);});editor.addEventListener("paste",(e)=>{const items=e.clipboardData.items;for(let i=0;i<items.length;i++){const item=items[i];if(item.type.startsWith("image/")){const file=item.getAsFile();compressImage(file,800,0.7,insertImageBlob);e.preventDefault();}}});function initVisibilityPopup({popId,width=550,height=350}={}){ if (window.opener) return; let popup=null;const sourceContent=document.querySelector(popId);if(!sourceContent)return;const openPopup=()=>{if(popup &&!popup.closed)return;const left=(screen.width-width)/ 2;const top=(screen.height-height)/ 2;popup=window.open("","_blank",`width=${width},height=${height},left=${left},top=${top}`);if(!popup){console.error("Popup blocked!");return;}const pd=popup.document;pd.title=document.title;document.querySelectorAll('link[rel="icon"],link[rel="shortcut icon"],link[rel="stylesheet"],style').forEach(tag=>{const clone=tag.cloneNode(true);if(clone.href)clone.href=new URL(clone.getAttribute("href"),location.href).href;pd.head.appendChild(clone);});pd.body.innerHTML=`<style>header{display:none;}</style>${sourceContent.innerHTML}`;document.querySelectorAll('script').forEach(s=>{const clone=document.createElement('script');if(s.src)clone.src=new URL(s.src,location.href).href;else clone.textContent=s.textContent;pd.body.appendChild(clone);});};const closePopup=()=>{if(popup &&!popup.closed){popup.close();popup=null; window.location.reload();}};document.addEventListener("visibilitychange",()=>{document.hidden?openPopup():closePopup();});}initVisibilityPopup({popId:"body"});
